    {
      "name": "fuel_prices",
      "displayName": "Fuel Prices",
      "queryLines": [
        "SELECT year_period, fuel_type, city, price_cpl FROM danny_catalog.dem_schema.aip_terminal_gate_prices"
      ]
    },
    {
      "name": "adelaide_prices",
      "displayName": "Adelaide Prices",
      "queryLines": [
        "SELECT year_period, fuel_type, price_cpl FROM danny_catalog.dem_schema.aip_terminal_gate_prices WHERE city = 'Adelaide' ORDER BY year_period"
      ]
    },
    {
      "name": "latest_ulp",
      "displayName": "Latest ULP",
      "queryLines": [
        "SELECT ROUND(AVG(price_cpl),1) as price_cpl FROM danny_catalog.dem_schema.aip_terminal_gate_prices WHERE city='Adelaide' AND fuel_type='ULP' AND year_period=(SELECT MAX(year_period) FROM danny_catalog.dem_schema.aip_terminal_gate_prices)"
      ]
    },
    {
      "name": "latest_diesel",
      "displayName": "Latest Diesel",
      "queryLines": [
        "SELECT ROUND(AVG(price_cpl),1) as price_cpl FROM danny_catalog.dem_schema.aip_terminal_gate_prices WHERE city='Adelaide' AND fuel_type='Diesel' AND year_period=(SELECT MAX(year_period) FROM danny_catalog.dem_schema.aip_terminal_gate_prices)"
      ]
    },
    {
      "name": "petrol_sales",
      "displayName": "Petroleum Sales",
      "queryLines": [
        "SELECT source_sheet, data_category, COUNT(*) as record_count FROM danny_catalog.dem_schema.petroleum_sales_by_state GROUP BY source_sheet, data_category"
      ]
    },
    {
      "name": "petrol_sales_count",
      "displayName": "Sales Count",
      "queryLines": [
        "SELECT COUNT(*) as cnt FROM danny_catalog.dem_schema.petroleum_sales_by_state"
      ]
    },
    {
      "name": "nger_top",
      "displayName": "Top Emitters",
      "queryLines": [
        "SELECT Organisation_name, CAST(REPLACE(`Total_scope_1_emissions_t_CO2-e`, ',', '') AS BIGINT) as scope1_tonnes, CAST(REPLACE(`Total_scope_2_emissions_t_CO2-e`, ',', '') AS BIGINT) as scope2_tonnes FROM danny_catalog.dem_schema.nger_corporate_emissions WHERE `Total_scope_1_emissions_t_CO2-e` != '' ORDER BY scope1_tonnes DESC LIMIT 15"
      ]
    },
    {
      "name": "nger_count",
      "displayName": "Emitter Count",
      "queryLines": [
        "SELECT COUNT(*) as cnt FROM danny_catalog.dem_schema.nger_corporate_emissions"
      ]
    },
    {
      "name": "stocks",
      "displayName": "Stock Volumes",
      "queryLines": [
        "SELECT Month, 'Crude Oil' as Product, Crude_oil_and_refinery_feedstocks_ML as Volume_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'UNION ALL SELECT Month, 'Diesel', Diesel_oil_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'UNION ALL SELECT Month, 'Gasoline', Automotive_gasoline_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'UNION ALL SELECT Month, 'Aviation Fuel', Aviation_turbine_fuel_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'UNION ALL SELECT Month, 'LPG', LPG_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'UNION ALL SELECT Month, 'Fuel Oil', Fuel_oil_ML FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Stock volume by product'ORDER BY Month, Product"
      ]
    },
    {
      "name": "supply_cover",
      "displayName": "Supply Coverage Days",
      "queryLines": [
        "SELECT Month, 'Crude Oil' as Fuel_Type, Crude_oil_and_refinery_feedstocks_days as Days_Cover FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Consumption cover'UNION ALL SELECT Month, 'Gasoline', Automotive_gasoline_days FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Consumption cover'UNION ALL SELECT Month, 'Diesel', Diesel_oil_days FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Consumption cover'UNION ALL SELECT Month, 'Aviation Fuel', Aviation_turbine_fuel_days FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Consumption cover'UNION ALL SELECT Month, 'LPG', LPG_days FROM danny_catalog.dem_schema.petroleum_stocks WHERE source_sheet = 'Consumption cover'ORDER BY Month, Fuel_Type"
      ]
    },
    {
      "name": "latest_total_stock",
      "displayName": "Latest Total Stock",
      "queryLines": [
        "SELECT\n",
        "  ROUND(Total_stocks_COE_ML, 0) as total_stock_ml\n",
        "FROM\n",
        "  danny_catalog.dem_schema.petroleum_stocks\n",
        "WHERE\n",
        "  source_sheet = 'Stock volume by product'\n",
        "  AND Month\n",
        "    = (\n",
        "      SELECT\n",
        "        MAX(Month)\n",
        "      FROM\n",
        "        danny_catalog.dem_schema.petroleum_stocks\n",
        "    )"
      ]
    },
    {
      "name": "sales_by_state",
      "displayName": "Sales by State",
      "queryLines": [
        "SELECT\n",
        "  State,\n",
        "  'Gasoline' as Fuel_Type,\n",
        "  ROUND(SUM(`Automotive_gasoline:_total_ML`), 0) as Sales_ML\n",
        "FROM\n",
        "  danny_catalog.dem_schema.petroleum_sales_by_state\n",
        "WHERE\n",
        "  source_sheet = 'Sales by state and territory'\n",
        "  AND Month >= '2025-01-01'\n",
        "  AND State IS NOT NULL\n",
        "GROUP BY\n",
        "  State\n",
        "UNION ALL\n",
        "SELECT\n",
        "  State,\n",
        "  'Diesel',\n",
        "  ROUND(SUM(`Diesel_oil:_total`), 0)\n",
        "FROM\n",
        "  danny_catalog.dem_schema.petroleum_sales_by_state\n",
        "WHERE\n",
        "  source_sheet = 'Sales by state and territory'\n",
        "  AND Month >= '2025-01-01'\n",
        "  AND State IS NOT NULL\n",
        "GROUP BY\n",
        "  State\n",
        "ORDER BY\n",
        "  Sales_ML DESC"
      ]
    },
